import { CreateInvoiceSchema as InvoiceDto } from '../dtos/invoice.dto';

export async function createInvoice(req: Request, res: Response) {
  // Validação Zod do body é a primeira coisa do handler — nada roda antes disso.
  const parsed = InvoiceDto.safeParse(req.body);
  if (!parsed.success) {
    return res
      .status(400)
      .json({
        success: false,
        error: parsed.error.flatten(),
      });
  }

  try {
    const actor = getUserContextFromRequest(req);
    const service = getFactory().getInvoiceService();
    const invoice = await service.create(actor, parsed.data);
    return res.status(201).json({ success: true, data: invoice });
  } catch (error) {
    return handleApiError(error, res);
  }
}

export async function createInvoice(req: Request, res: Response): Promise<Response> {
  try {
    const parseResult = createInvoiceSchema.safeParse(req.body);

    if (parseResult.success === false) {
      return res.status(400).json({ error: parseResult.error.flatten(), success: false });
    }

    const payload = parseResult.data;
    const actor = getUserContextFromRequest(req);
    const invoiceService = getFactory().getInvoiceService();
    const invoice = await invoiceService.create(actor, payload);

    return res.status(201).json({ success: true, data: invoice });
  } catch (error) {
    return handleApiError(error, res);
  }
}

